#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=5e4+5;
struct node
{
	int begin,end,k;
}a[MAXN];
bool cmp(node a,node b)
{
	return a.end<b.end;
}
bool b[MAXN];
int n,m,ans=0;
int main(void){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;++i)
	{
		scanf("%d%d%d",&a[i].begin,&a[i].end,&a[i].k);
	}
	sort(a+1,a+m+1,cmp);
	for(int i=1;i<=m;++i)
	{
		int sum=0,cnt=0;
		for(int j=a[i].begin;j<=a[i].end;++j)
		{
			sum+=b[j];
		}
        if(sum>=a[i].k)
		{
			continue;
		}
		for(int j=a[i].end;j>=a[i].begin;--j)
		{
            if(cnt==a[i].k-sum)
			{
				break;
			}
            if(b[j]==true)
			{
				continue;
			}
            else b[j]=true,ans++,cnt++;
        }
	}
	printf("%d",ans);
	return false;
}
